module.exports = function (data) {
  const trigger = data.$trigger || {};
  const payload = trigger.payload || {};
  const keys = trigger.keys || [];
  const event = trigger.event || "";

  const hasOwn = (key) => Object.prototype.hasOwnProperty.call(payload, key);
  const titleChanged = hasOwn("title");
  const bodyChanged = hasOwn("body_markdown");
  const shouldProcess = event === "items.create" || titleChanged || bodyChanged;

  return {
    should_process: shouldProcess,
    item_id: payload.id ?? keys[0] ?? null,
    title_override: titleChanged ? payload.title : null,
    body_override: bodyChanged ? payload.body_markdown : null
  };
};

module.exports = function (data) {
  const context = data.prepare_content_hash_context || {};
  const currentRow = Array.isArray(data.read_current_blog_post) ? data.read_current_blog_post[0] || {} : {};

  const title = context.title_override !== null ? context.title_override : currentRow.title ?? "";
  const bodyMarkdown = context.body_override !== null ? context.body_override : currentRow.body_markdown ?? "";

  const input = `${title}\n${bodyMarkdown}`;

  let hash = 2166136261;
  for (let i = 0; i < input.length; i += 1) {
    hash ^= input.charCodeAt(i);
    hash = (hash * 16777619) >>> 0;
  }

  const contentHash = hash.toString(16).padStart(8, "0");

  return {
    item_id: context.item_id,
    content_hash: contentHash
  };
};
